"use strict";

module.exports = {
  slug:  "access-control",
  title: "Access Control",
  body: [
  '<h1>Access Control</h1>',
  '<p>Authorization layers on top of <a href="/auth">authentication</a>. <code>b.permissions</code> for RBAC, <code>b.apiKey</code> for issued credentials, <code>b.breakGlass</code> for column-level second-factor gates, and <code>b.credentialHash</code> as the underlying password-hash envelope shared by passwords and api-keys.</p>',

  '<h2 id="rbac">Permissions (RBAC) <a class="anchor" href="#rbac">#</a></h2>',
  '<p>Role-based access control. Roles inherit; permissions are flat strings; the resolver decides which roles each actor carries.</p>',
  '<h3>b.permissions.create(opts)</h3>',
  '<pre><code class="language-javascript">{',
  '  roles:                { [name]: { allow, inherits } },',
  '                                           // required: true',
  '  resolver:             (req) =&gt; string[],// default: apiKey.scopes → user.scopes → user.roles',
  '  audit:                AuditTap,          // default: null',
  '  auditFailures:        boolean,           // default: true',
  '  auditSuccess:         boolean,           // default: true',
  '  denyStatus:           number,            // default: 403',
  '  missingActorStatus:   number,            // default: 401',
  '  responder:            (req, res, status, info) =&gt; void,',
  '                                           // default: writes JSON 401/403',
  '}</code></pre>',
  '<pre><code class="language-javascript">var perms = b.permissions.create({',
  '  roles: {',
  '    viewer:  { allow: ["page:read"] },',
  '    editor:  { inherits: ["viewer"], allow: ["page:write", "page:publish"] },',
  '    admin:   { inherits: ["editor"], allow: ["*"] },',
  '  },',
  '  resolver: function (req) { return (req.user &amp;&amp; req.user.roles) || []; },',
  '  audit:   b.audit,',
  '});',
  '',
  'router.post("/admin/save",',
  '  perms.require("page:write"),',
  '  saveHandler,',
  ');',
  '',
  '// Programmatic check elsewhere:',
  'var ok = perms.check(req.user, "page:publish");</code></pre>',
  '<p>Every check that runs through <code>middleware()</code> emits an audit row carrying the requested permission, the actor\'s resolved roles, and the outcome. <code>permissions.check()</code> called directly is silent unless wired with <code>{ audit }</code> per call site.</p>',
  '<p>Wildcards: <code>"page.*"</code> matches <code>page:read</code>, <code>page:write</code>, etc. <code>"*"</code> at the role level grants every permission (admin shorthand). Cycle detection in <code>inherits</code> at create-time — an accidental <code>A inherits B inherits A</code> throws at boot rather than producing surprise authorization decisions in production.</p>',

  '<h2 id="api-keys">API keys <a class="anchor" href="#api-keys">#</a></h2>',
  '<p><code>b.apiKey</code> issues namespaced keys for machine-to-machine traffic. The plaintext secret is shown to the operator exactly once on issuance; the DB stores a SHAKE256 hash inside the same envelope used by <code>b.credentialHash</code> (operators paranoid about low-entropy storage opt into Argon2id per registry).</p>',
  '<h3>b.apiKey.create(opts)</h3>',
  '<pre><code class="language-javascript">{',
  '  namespace:        string,                // required: true — table-key prefix + token prefix',
  '  prefix:           string,                // default: "bk"',
  '  idBytes:          number,                // default: 8 — 16 hex chars',
  '  secretBytes:      number,                // default: 16 — 32 hex chars',
  '  trackLastUsedAt:  boolean,               // default: true',
  '  auditFailures:    boolean,               // default: true',
  '  auditSuccess:     boolean,               // default: true',
  '  purgeAfterMs:     number,                // default: C.TIME.days(90)',
  '  hashAlgo:         "shake256" | "argon2id",',
  '                                           // default: "shake256"',
  '  audit:            AuditTap,              // default: null',
  '  clock:            () =&gt; number,          // default: Date.now',
  '}</code></pre>',
  '<h3>keys.issue(opts) / keys.rotate(id, opts)</h3>',
  '<pre><code class="language-javascript">// issue:',
  '{',
  '  ownerId:   string,                       // required: true',
  '  scopes:    string[],                     // default: []',
  '  metadata:  object,                       // default: null — sealed-at-rest',
  '  expiresAt: number,                       // default: null — ms epoch',
  '}',
  '',
  '// rotate:',
  '{',
  '  gracePeriodMs: number,                   // default: C.TIME.days(7)',
  '}</code></pre>',
  '<pre><code class="language-javascript">var keys = b.apiKey.create({',
  '  namespace: "wiki",',
  '  audit:     b.audit,',
  '});',
  '',
  'var issued = await keys.issue({ ownerId: "u-42", scopes: ["page:read"] });',
  'console.log(issued.key);  // "wiki_pk_..." — show once',
  '',
  '// Verify on each request',
  'var record = await keys.verify(req.headers["authorization"]);',
  'if (!record) return res.status(401).end();',
  '',
  '// Rotate without breaking clients',
  'var rotated = await keys.rotate(record.id, { gracePeriodMs: C.TIME.days(7) });',
  '// Old key keeps verifying for 7 days; new key works immediately.',
  '',
  '// List + revoke + purge',
  'var owned = await keys.listForOwner("u-42");',
  'await keys.revoke(record.id);',
  'await keys.purgeExpired();   // batch op — emits audit row with the purged ids</code></pre>',
  '<p>Issue, verify, rotate, revoke, purge, last-used-at all emit on the audit chain by default with the actor\'s 5 W\'s threaded through. Verify-success can be disabled per-namespace for high-volume credentials; failures stay on regardless.</p>',

  '<h3 id="api-keys-cli">CLI surface <a class="anchor" href="#api-keys-cli">#</a></h3>',
  '<p>For deployments without an admin UI, <code>blamejs api-key</code> drives the same operations from the command line. The CLI boots a headless app instance against <code>--data-dir</code>, runs the operation, and shuts down — same vault + DB + audit chain the running app uses, just no HTTP surface.</p>',
  '<pre><code class="language-bash"># Issue a new key',
  'BLAMEJS_VAULT_PASSPHRASE="..." \\',
  'blamejs api-key issue \\',
  '  --data-dir   ./data \\',
  '  --namespace  api \\',
  '  --owner-id   u-42 \\',
  '  --scopes     "users:read,users:write" \\',
  '  --label      "ci-runner key"',
  '',
  '# List active keys for an owner',
  'blamejs api-key list --data-dir ./data --namespace api --owner-id u-42',
  '',
  '# Rotate (new secret; old keeps verifying for --grace-ms)',
  'blamejs api-key rotate --data-dir ./data --namespace api --id 51b8...6310 --grace-ms 86400000',
  '',
  '# Revoke',
  'blamejs api-key revoke --data-dir ./data --namespace api --id 51b8...6310',
  '',
  '# Verify a token (debug an integration that\'s seeing 401s)',
  'blamejs api-key verify --data-dir ./data --namespace api --token bk_api_...</code></pre>',

  '<h2 id="break-glass">Break-glass column access <a class="anchor" href="#break-glass">#</a></h2>',
  '<p><code>b.breakGlass</code> gates reads of operator-marked sensitive columns (PHI, credit card fields, SSN, diagnosis, etc.) behind a per-row second-factor authentication. Operator marks columns at the schema level; every row read of those columns requires a fresh, scope-bounded grant tied to a second factor and a documented reason. Each unseal emits a per-row audit event with the 5 W\'s, the grant id, the columns touched, and the reason. Post-incident review can answer "who looked at row #12345 at 14:32, why, and from where".</p>',
  '<p>Default <code>maxRowsPerGrant: 1</code> — each row access is its own discrete authenticated event. Operators with batch workflows (compliance reports etc.) raise the cap explicitly per-table. <code>grantTtl: 15 minutes</code> default. <code>pinIp</code> + <code>sessionPin</code> default <code>true</code> so a stolen grant id can\'t be replayed from a different network or session.</p>',
  '<h3>b.breakGlass.policy.set(table, opts)</h3>',
  '<pre><code class="language-javascript">{',
  '  columns:               string[],         // required: true',
  '  factors:               ("totp" | "passkey")[],',
  '                                           // required: true',
  '  cryptographic:         boolean,          // default: false — per-cell encryption + AAD bind',
  '  grantTtl:              number,           // default: C.TIME.minutes(15)',
  '  maxRowsPerGrant:       number,           // default: 1 — row-by-row auth',
  '  reasonRequired:        boolean,          // default: true',
  '  reasonMinLength:       number,           // default: 12',
  '  pinIp:                 boolean,          // default: true',
  '  sessionPin:            boolean,          // default: true',
  '  onLockedAccess:        "throw" | "redact",',
  '                                           // default: "throw"',
  '  serviceAccountBypass:  { enabled, apiKeyIds, requireRole },',
  '                                           // default: null',
  '}</code></pre>',
  '<h3>b.breakGlass.grant(opts)</h3>',
  '<pre><code class="language-javascript">{',
  '  req:     IncomingRequest,                // required: true — actor context',
  '  table:   string,                         // required: true',
  '  reason:  string,                         // required: true (when reasonRequired)',
  '  factor:  { type: "totp" | "passkey", ... },',
  '                                           // required: true',
  '}</code></pre>',
  '<pre><code class="language-javascript">// Boot: declare which columns are glass-locked',
  'b.breakGlass.init();',
  'await b.breakGlass.policy.set("patients", {',
  '  columns:         ["ssn", "diagnosis", "notes"],',
  '  factors:         ["totp"],',
  '  // Defaults shown for clarity:',
  '  // grantTtl:        b.constants.TIME.minutes(15),',
  '  // maxRowsPerGrant: 1,        // row-by-row auth',
  '  // reasonRequired:  true,',
  '  // reasonMinLength: 12,',
  '  // pinIp:           true,',
  '  // sessionPin:      true,',
  '  // onLockedAccess:  "throw",  // or "redact"',
  '});',
  '',
  '// Operator presents second factor + reason → gets a grant',
  'router.post("/admin/patients/:id/unseal-ssn", async function (req, res) {',
  '  var grant = await b.breakGlass.grant({',
  '    req:    req,',
  '    table:  "patients",',
  '    reason: req.body.reason,                  // operator typed it in the UI',
  '    factor: { type: "totp",',
  '              code:   req.body.totpCode,',
  '              secret: req.user.totpSecret },',
  '  });',
  '  // Use the grant to unseal exactly one row (default cap)',
  '  var row = await b.breakGlass.unsealRow(grant, "patients", req.params.id);',
  '  res.json({ ssn: row.ssn });',
  '});</code></pre>',
  '<p>Audit chain (namespace <code>breakglass</code>) records every step: <code>breakglass.policy.set</code>, <code>breakglass.grant.requested</code> (success/denied), <code>breakglass.unsealrow</code> (per-row), <code>breakglass.grant.exhausted</code>, <code>breakglass.grant.expired</code>, <code>breakglass.grant.revoked</code>. The actor 5 W\'s populate on every event.</p>',
  '<p>By default glass-locked columns stay sealed under the framework\'s vault key — the gate is enforced at the <code>unsealRow</code> API. Set <code>cryptographic: true</code> on a policy to switch the columns to per-cell encryption with encryption-context binding (next section).</p>',

  '<h3 id="break-glass-cryptographic">Per-cell encryption with context binding <a class="anchor" href="#break-glass-cryptographic">#</a></h3>',
  '<p>With <code>cryptographic: true</code>, each glass-locked cell is encrypted under a unique key derived from <code>SHAKE256(DEK || table || rowId || column)</code>, and the AEAD tag binds <code>(table, rowId, column)</code> as additional authenticated data. A ciphertext from row A literally cannot be decrypted as row B — accidental cross-row decrypt or deliberate ciphertext-swap tampering fails closed at the cryptographic layer, not just at a runtime check.</p>',
  '<pre><code class="language-javascript">await b.breakGlass.policy.set("patients", {',
  '  columns:       ["ssn", "diagnosis"],',
  '  factors:       ["totp"],',
  '  cryptographic: true,',
  '});',
  '',
  '// At write time, encrypt cells explicitly so the cipher binds to',
  '// (table, rowId, column):',
  'var ssnCipher = await b.breakGlass.encryptCell(rawSsn, {',
  '  table: "patients", rowId: patientId, column: "ssn",',
  '});',
  'await b.db.from("users").insertOne({ _id: patientId, name: "p", ssn: ssnCipher });',
  '',
  '// Reads use the same grant flow — unsealRow returns plaintext for',
  '// the glass-locked columns when a valid grant is presented.',
  'var grant = await b.breakGlass.grant({ req, table: "patients", reason, factor });',
  'var row = await b.breakGlass.unsealRow(grant, "patients", patientId);',
  '',
  '// Convert existing tables in batches:',
  'var result = await b.breakGlass.migrate("patients", { batchSize: 100 });',
  '// → { table, totalRows, migratedRows, skippedRows }',
  '// Idempotent: cells already in this format are skipped.</code></pre>',
  '<p><strong>What this defends against:</strong> compromise of one cell\'s key doesn\'t compromise others (per-cell unique keys), and ciphertext-swap attacks across rows fail at decrypt time (the AEAD tag rejects mismatched context).</p>',
  '<p><strong>What this does NOT defend against:</strong> compromise of the framework\'s vault key alone. The per-policy data-encryption key is vault-sealed at rest, so an attacker holding the vault key can recover it. Defense against vault-key-alone compromise requires a second factor whose cryptographic material the framework never holds (e.g. a hardware-backed key on the operator\'s device).</p>',
  '<p><strong>Compliance.</strong> The audit chain is tamper-evident (SLH-DSA-signed checkpoints + monotonic counter) and every grant + unseal carries the actor 5 W\'s, the reason string, and the row id — sufficient for HIPAA §164.312(b), PCI-DSS 4.0 §10.2.1, and NIST SP 800-53 AU-12 audit-record-generation requirements. The mandatory reason field + short default TTL + per-row default cap correspond to NIST AC-2(2) "audited override of automated access control mechanisms" and HIPAA §164.312(a)(2)(ii) automatic logoff.</p>',

  '<h3 id="break-glass-passkey">Passkey factor <a class="anchor" href="#break-glass-passkey">#</a></h3>',
  '<p>Operators with WebAuthn / passkey enrollment can use it as the second factor instead of TOTP. The private key lives on the user\'s authenticator (YubiKey, platform passkey) — phishing-resistant, replay-resistant, and the framework\'s vault never holds the key material.</p>',
  '<pre><code class="language-javascript">await b.breakGlass.policy.set("patients", {',
  '  columns: ["ssn"],',
  '  factors: ["passkey"],',
  '});',
  '',
  '// Operator presents an assertion (produced by navigator.credentials.get',
  '// in the browser) plus the expected challenge / origin / RPID + the',
  '// previously-enrolled credential record:',
  'var grant = await b.breakGlass.grant({',
  '  req,',
  '  table:  "patients",',
  '  reason: req.body.reason,',
  '  factor: {',
  '    type:               "passkey",',
  '    response:           req.body.assertion,',
  '    expectedChallenge:  req.session.bgChallenge,',
  '    expectedOrigin:     "https://wiki.example.com",',
  '    expectedRPID:       "wiki.example.com",',
  '    credential:         user.passkeyCredential,',
  '  },',
  '});</code></pre>',

  '<h3 id="break-glass-service-account">Service-account bypass <a class="anchor" href="#break-glass-service-account">#</a></h3>',
  '<p>Some workflows (nightly de-identification jobs, scheduled compliance reports) need PHI access without a human at the keyboard. The framework refuses to silently bypass — operators declare an explicit allowlist of <code>apiKey</code> ids that may bypass, plus a required role/scope. Both must match before the bypass is granted, and every bypass emits a distinct <code>breakglass.grant.bypass</code> audit row so post-incident review can distinguish operator-initiated reads from service-initiated reads.</p>',
  '<pre><code class="language-javascript">await b.breakGlass.policy.set("patients", {',
  '  columns: ["ssn", "diagnosis"],',
  '  factors: ["totp"],',
  '  serviceAccountBypass: {',
  '    enabled:     true,',
  '    apiKeyIds:   ["ak-svc-deidentify-job"],   // exact apiKey ids that may bypass',
  '    requireRole: "service:phi-reader",',
  '  },',
  '});',
  '',
  '// In the cron handler — req.apiKey was set by the requireApiKey middleware:',
  'var row = await b.breakGlass.unsealRowAsService(req, "patients", patientId,',
  '  { reason: "nightly de-identification batch #" + batchId });</code></pre>',

  '<h3 id="break-glass-admin">Admin tools <a class="anchor" href="#break-glass-admin">#</a></h3>',
  '<pre><code class="language-javascript">// List every active grant — for security dashboards, anomaly detection.',
  'var all = await b.breakGlass.listActiveAll({ table: "patients", since: Date.now() - C.TIME.hours(24) });',
  '',
  '// Mass-revoke during incident response (compromised account, abrupt offboarding).',
  'await b.breakGlass.revokeAll(',
  '  { actorId: "user-suspicious", reason: "ir-2026-04-30 token rotation" }',
  ');',
  '// → { revokedCount: 12 }   // emits one audit row with the full revoked id list</code></pre>',

  '<h2 id="credential-hash">Credential hash <a class="anchor" href="#credential-hash">#</a></h2>',
  '<p>The shared envelope under password and api-key hashing. Four-byte header followed by an algorithm-specific body — SHAKE256 (default) or Argon2id PHC. Existing rows continue to verify even after the active algorithm or parameters move forward; new rows pick up whatever <code>b.credentialHash.ACTIVE</code> resolves to at write time. Operators rolling forward parameters call <code>credentialHash.rehashIfStale(stored, plaintext)</code> on next login and write back the result.</p>',
  '<h3>b.credentialHash.hash(secret, opts) / .verify(stored, secret) / .rehashIfStale(stored, secret)</h3>',
  '<pre><code class="language-javascript">// hash opts:',
  '{',
  '  algo:    "shake256" | "argon2id",       // default: "shake256"',
  '  params:  {',
  '    length:        number,                // SHAKE256 only — digest size, default: 128',
  '    memoryCost:    number,                // argon2id — passed to b.password',
  '    timeCost:      number,                // argon2id — passed to b.password',
  '    parallelism:   number,                // argon2id — passed to b.password',
  '  },                                      // default: null (registry values)',
  '}</code></pre>',
  '<pre><code class="language-javascript">// Hash on credential set:',
  'var stored = await b.credentialHash.hash(secret);',
  '// store `stored` in the DB column — opaque envelope',
  '',
  '// Verify on each presentation:',
  'var ok = await b.credentialHash.verify(stored, presented);',
  '',
  '// Roll forward parameters on successful verify when the row is stale:',
  'if (ok && b.credentialHash.needsRehash(stored)) {',
  '  var refreshed = await b.credentialHash.hash(presented);',
  '  await b.db.from("users").where({ _id: userId }).updateOne({ secretHash: refreshed });',
  '}</code></pre>',

  '<h2 id="abac">Context-aware authorization (ABAC) <a class="anchor" href="#abac">#</a></h2>',
  '<p>RBAC says <em>which</em> scopes the actor holds. ABAC says <em>under what conditions</em> the action is allowed — "alice may read order X if alice owns order X". <code>perms.policy(scope, predicate)</code> registers a predicate the middleware evaluates AFTER the scope check; both layers must pass.</p>',
  '<h3>perms.policy(scope, predicate) <a class="anchor" href="#abac-policy">#</a></h3>',
  '<p>Predicate signature: <code>(actor, context) =&gt; boolean | Promise&lt;boolean&gt;</code>. Context is whatever the per-route <code>context</code> opt returns. Throwing or returning falsy denies; the middleware audits <code>permissions.policy.deny</code>.</p>',
  '<pre><code class="language-javascript">perms.policy("orders:read", function (actor, ctx) {',
  '  if (actor.roles && actor.roles.indexOf("admin") !== -1) return true;',
  '  return ctx && ctx.resource && ctx.resource.ownerId === actor.userId;',
  '});',
  '',
  'router.get("/orders/:id",',
  '  attachUserMw,',
  '  perms.require("orders:read", {',
  '    context: async function (req) {',
  '      var row = b.db.prepare("SELECT ownerId FROM orders WHERE id = ?").get(req.params.id);',
  '      return { resource: row };',
  '    },',
  '  }),',
  '  function (req, res) { res.json({ id: req.params.id }); }',
  ');</code></pre>',

  '<h2 id="mfa-required">MFA enforcement on privileged scopes <a class="anchor" href="#mfa-required">#</a></h2>',
  '<p>Per-route or per-role: a route guarded by a scope that requires MFA blocks unless the actor was authenticated through a step-up factor (TOTP, passkey) AND (when <code>mfaWindowMs</code> is set) the step-up timestamp is fresh. The actor signal is operator-set: after a successful step-up, the route handler stamps <code>req.user.mfaAuthenticated = true</code> and <code>req.user.mfaAt = Date.now()</code>.</p>',
  '<pre><code class="language-javascript">// Per-role enforcement — every scope this role grants requires MFA',
  'var perms = b.permissions.create({',
  '  roles: {',
  '    admin: {',
  '      permissions: ["users:delete", "billing:write"],',
  '      requireMfa:  true,',
  '      mfaWindowMs: b.constants.TIME.minutes(15),',
  '    },',
  '  },',
  '});',
  '',
  '// Per-route enforcement — overrides per-role',
  'router.delete("/users/:id",',
  '  attachUserMw,',
  '  perms.require("users:delete", { requireMfa: true, mfaWindowMs: b.constants.TIME.minutes(5) }),',
  '  deleteUserHandler);</code></pre>',
  '<p>Failure surfaces as <code>403 mfa_required</code> + <code>permissions.mfa.required</code> on the audit chain. Operators redirect the client into the step-up flow; on success they stamp the freshness window and let the request proceed.</p>',
].join("\n"),
};
